package be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementPropertyCalculator;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.add.BedragVerdelerAdd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.put.BedragVerdelerPut;
import be.schaubroeck.lpb.tools.Money;

import java.util.Collection;

public final class BedragVerdelerFactory {
    private BedragVerdelerFactory() {
    }

    public static BedragVerdeler createAdd(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        return new BedragVerdelerAdd(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen, checker);
    }

    public static BedragVerdeler createAdd(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen) {
        return new BedragVerdelerAdd(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen);
    }

    public static void verdeelBedragVolgensBasisAdd(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        BedragVerdeler bedragVerdeler = createAdd(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen, checker);
        bedragVerdeler.verdeelBedragVolgensBasis();
    }

    public static void verdeelBedragVolgensBasisAdd(MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen) {
        BedragVerdeler bedragVerdeler = createAdd(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen);
        bedragVerdeler.verdeelBedragVolgensBasis();
    }

    public static BedragVerdeler createPut(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        return new BedragVerdelerPut(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen, checker);
    }

    public static BedragVerdeler createPut(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen) {
        return new BedragVerdelerPut(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen);
    }

    public static BedragVerdeler createPut(
            MoneyKey bedragKey, Money totaalBedrag, LoonElementPropertyCalculator basisCalculator, Money totaalBasis, Collection<LoonElement> loonElementen,
            LoonElementChecker checker) {
        return new BedragVerdelerPut(bedragKey, totaalBedrag, basisCalculator, totaalBasis, loonElementen, checker);
    }

    public static void verdeelBedragVolgensBasisPut(MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen) {
        BedragVerdeler bedragVerdeler = createPut(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen);
        bedragVerdeler.verdeelBedragVolgensBasis();
    }

    public static void verdeelBedragVolgensBasisPut(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        BedragVerdeler bedragVerdeler = createPut(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen, checker);
        bedragVerdeler.verdeelBedragVolgensBasis();
    }

    public static void verdeelBedragVolgensBasisPut(
            MoneyKey bedragKey, Money totaalBedrag, LoonElementPropertyCalculator basisCalculator,
            Money totaalBasis, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        BedragVerdeler bedragVerdeler = createPut(bedragKey, totaalBedrag, basisCalculator, totaalBasis, loonElementen, checker);
        bedragVerdeler.verdeelBedragVolgensBasis();
    }
}
